import * as React from 'react';
import { navigate } from 'gatsby';
import MuiLink from '@mui/material/Link';

const Link = props => {
  const { href } = props;

  return (
    <MuiLink
      href={href}
      onClick={e => {
        if (!props?.target || props?.target !== '_blank') {
          e.preventDefault();
          navigate(href);
        }
      }}
      {...props}
    >
      {props?.children}
    </MuiLink>
  );
};

export default Link;
